"use client";

import { Button } from "@/components/ui/button";
import {
  Stepper,
  StepperIndicator,
  StepperItem,
  StepperTrigger,
} from "@/components/ui/stepper";
import { ChevronLeftIcon } from "lucide-react";

export default function MultiFormProgressIndicator({
  totalSteps = 3,
  currentStep,
  onPrevious,
  onNext,
  actions = true,
}: {
  totalSteps: number;
  currentStep: number;
  onPrevious: () => void;
  onNext: () => void;
  actions?: boolean;
}) {
  const steps = Array(totalSteps)
    .fill("")
    .map((_, i) => i + 1);

  return (
    <div className="relative mx-auto w-full max-w-xl space-y-8 text-center">
      <div className="flex items-center gap-2">
        {actions ? (
          <Button
            className="shrink-0"
            variant="ghost"
            size="icon"
            onClick={onPrevious}
            disabled={currentStep === 1}
            aria-label="Prev step"
          >
            <ChevronLeftIcon size={16} aria-hidden="true" />
          </Button>
        ) : null}
        <Stepper value={currentStep} onValueChange={onNext} className="gap-1">
          {steps.map((step) => (
            <StepperItem key={step} step={step} className="flex-1">
              <StepperTrigger
                className="w-full flex-col items-start gap-2"
                asChild
              >
                <StepperIndicator asChild className="h-1 w-full bg-border">
                  <span className="sr-only">{step}</span>
                </StepperIndicator>
              </StepperTrigger>
            </StepperItem>
          ))}
        </Stepper>
      </div>
    </div>
  );
}

import { DialogFooter } from "@/components/ui/dialog";
import { Field } from "@/components/ui/field";
import StepperNextButton from "./StepperNextButton";
import StepperPreviousButton from "./StepperPreviousButton";

function MultiStepFormFooter() {
  return (
    <DialogFooter>
      <Field orientation="horizontal" className="flex w-full justify-end">
        <StepperPreviousButton />
        <StepperNextButton />
      </Field>
    </DialogFooter>
  );
}

export default MultiStepFormFooter;

import {
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { useMultiFormContext } from "@/hooks/use-stepped-form";

function MultiStepFormHeader() {
  const { currentStep } = useMultiFormContext();
  return (
    <DialogHeader>
      <DialogTitle>{currentStep.title}</DialogTitle>
      <DialogDescription>{currentStep.description}</DialogDescription>
    </DialogHeader>
  );
}

export default MultiStepFormHeader;

import * as React from 'react'
import { createContext, useContext } from 'react'
import { Slot } from '@radix-ui/react-slot'
import { CheckIcon, LoaderCircleIcon } from 'lucide-react'
import { cn } from '@/lib/utils'

// Types
type StepperContextValue = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: 'horizontal' | 'vertical'
}

type StepItemContextValue = {
  step: number
  state: StepState
  isDisabled: boolean
  isLoading: boolean
}

type StepState = 'active' | 'completed' | 'inactive' | 'loading'

// Contexts
const StepperContext = createContext<StepperContextValue | undefined>(undefined)
const StepItemContext = createContext<StepItemContextValue | undefined>(
  undefined
)

const useStepper = () => {
  const context = useContext(StepperContext)
  if (!context) {
    throw new Error('useStepper must be used within a Stepper')
  }
  return context
}

const useStepItem = () => {
  const context = useContext(StepItemContext)
  if (!context) {
    throw new Error('useStepItem must be used within a StepperItem')
  }
  return context
}

// Components
interface StepperProps extends React.HTMLAttributes<HTMLDivElement> {
  defaultValue?: number
  value?: number
  onValueChange?: (value: number) => void
  orientation?: 'horizontal' | 'vertical'
}

function Stepper({
  defaultValue = 0,
  value,
  onValueChange,
  orientation = 'horizontal',
  className,
  ...props
}: StepperProps) {
  const [activeStep, setInternalStep] = React.useState(defaultValue)

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (value === undefined) {
        setInternalStep(step)
      }
      onValueChange?.(step)
    },
    [value, onValueChange]
  )

  const currentStep = value ?? activeStep

  return (
    <StepperContext.Provider
      value={{
        activeStep: currentStep,
        setActiveStep,
        orientation,
      }}
    >
      <div
        data-slot='stepper'
        className={cn(
          'group/stepper inline-flex data-[orientation=horizontal]:w-full data-[orientation=horizontal]:flex-row data-[orientation=vertical]:flex-col',
          className
        )}
        data-orientation={orientation}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// StepperItem
interface StepperItemProps extends React.HTMLAttributes<HTMLDivElement> {
  step: number
  completed?: boolean
  disabled?: boolean
  loading?: boolean
}

function StepperItem({
  step,
  completed = false,
  disabled = false,
  loading = false,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep } = useStepper()

  const state: StepState =
    completed || step < activeStep
      ? 'completed'
      : activeStep === step
        ? 'active'
        : 'inactive'

  const isLoading = loading && step === activeStep

  return (
    <StepItemContext.Provider
      value={{ step, state, isDisabled: disabled, isLoading }}
    >
      <div
        data-slot='stepper-item'
        className={cn(
          'group/step flex items-center group-data-[orientation=horizontal]/stepper:flex-row group-data-[orientation=vertical]/stepper:flex-col',
          className
        )}
        data-state={state}
        {...(isLoading ? { 'data-loading': true } : {})}
        {...props}
      >
        {children}
      </div>
    </StepItemContext.Provider>
  )
}

// StepperTrigger
interface StepperTriggerProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  asChild?: boolean
}

function StepperTrigger({
  asChild = false,
  className,
  children,
  ...props
}: StepperTriggerProps) {
  const { setActiveStep } = useStepper()
  const { step, isDisabled } = useStepItem()

  if (asChild) {
    const Comp = asChild ? Slot : 'span'
    return (
      <Comp data-slot='stepper-trigger' className={className}>
        {children}
      </Comp>
    )
  }

  return (
    <button
      data-slot='stepper-trigger'
      className={cn(
        'inline-flex items-center gap-3 rounded-full outline-none focus-visible:z-10 focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50',
        className
      )}
      onClick={() => setActiveStep(step)}
      disabled={isDisabled}
      {...props}
    >
      {children}
    </button>
  )
}

// StepperIndicator
interface StepperIndicatorProps extends React.HTMLAttributes<HTMLDivElement> {
  asChild?: boolean
}

function StepperIndicator({
  asChild = false,
  className,
  children,
  ...props
}: StepperIndicatorProps) {
  const { state, step, isLoading } = useStepItem()

  return (
    <span
      data-slot='stepper-indicator'
      className={cn(
        'relative flex size-6 shrink-0 items-center justify-center rounded-full bg-muted text-xs font-medium text-muted-foreground data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground',
        className
      )}
      data-state={state}
      {...props}
    >
      {asChild ? (
        children
      ) : (
        <>
          <span className='transition-all group-data-loading/step:scale-0 group-data-loading/step:opacity-0 group-data-loading/step:transition-none group-data-[state=completed]/step:scale-0 group-data-[state=completed]/step:opacity-0'>
            {step}
          </span>
          <CheckIcon
            className='absolute scale-0 opacity-0 transition-all group-data-[state=completed]/step:scale-100 group-data-[state=completed]/step:opacity-100'
            size={16}
            aria-hidden='true'
          />
          {isLoading && (
            <span className='absolute transition-all'>
              <LoaderCircleIcon
                className='animate-spin'
                size={14}
                aria-hidden='true'
              />
            </span>
          )}
        </>
      )}
    </span>
  )
}

// StepperTitle
function StepperTitle({
  className,
  ...props
}: React.HTMLAttributes<HTMLHeadingElement>) {
  return (
    <h3
      data-slot='stepper-title'
      className={cn('text-sm font-medium', className)}
      {...props}
    />
  )
}

// StepperDescription
function StepperDescription({
  className,
  ...props
}: React.HTMLAttributes<HTMLParagraphElement>) {
  return (
    <p
      data-slot='stepper-description'
      className={cn('text-sm text-muted-foreground', className)}
      {...props}
    />
  )
}

// StepperSeparator
function StepperSeparator({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div
      data-slot='stepper-separator'
      className={cn(
        'm-0.5 bg-muted group-data-[orientation=horizontal]/stepper:h-0.5 group-data-[orientation=horizontal]/stepper:w-full group-data-[orientation=horizontal]/stepper:flex-1 group-data-[orientation=vertical]/stepper:h-12 group-data-[orientation=vertical]/stepper:w-0.5 group-data-[state=completed]/step:bg-primary',
        className
      )}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
}

import { Button } from "@/components/ui/button";
import { useMultiFormContext } from "@/hooks/use-stepped-form";

function StepperNextButton() {
  const { isLastStep, isLoading, nextStep } = useMultiFormContext();
  return isLastStep ? (
    <Button type="submit" disabled={isLoading}>
      Submit
    </Button>
  ) : (
    <Button
      type="button"
      onClick={(e) => {
        e.preventDefault();
        nextStep();
      }}
    >
      Next
    </Button>
  );
}

export default StepperNextButton;

import { ArrowLeft } from 'lucide-react'
import { useMultiFormContext } from '@/hooks/use-stepped-form'
import { Button } from '../ui/button'

function StepperPreviousButton() {
  const { isFirstStep, previousStep } = useMultiFormContext()
  return (
    <Button onClick={previousStep} disabled={isFirstStep} variant={'outline'}>
      <ArrowLeft />
      Go Back
    </Button>
  )
}

export default StepperPreviousButton

import { MultiStepFormContext } from "@/registry/new-york/multi-step-form/context/MultiStepFormContext";
import { useContext } from "react";
import { type MultiFormContextProps } from "../types";

export function useMultiFormContext<T extends Record<string, unknown>>() {
  const ctx = useContext(MultiStepFormContext);
  if (!ctx) {
    throw new Error(
      "useMultiFormContext must be used within MultiStepProvider",
    );
  }
  return ctx as unknown as MultiFormContextProps<T>;
}

import { createContext } from "react";
import { MultiFormContextProps } from "../types";

export const MultiStepFormContext =
  createContext<MultiFormContextProps<any> | null>(null);

export const MultiStepFormProvider = <T extends Record<string, unknown>>({
  value,
  children,
}: {
  value: MultiFormContextProps<T>;
  children: React.ReactNode;
}) => {
  return (
    <MultiStepFormContext.Provider value={value}>
      {children}
    </MultiStepFormContext.Provider>
  );
};
